			}

			tracingProvider = tracesdk.NewTracerProvider(
				tracesdk.WithBatcher(
					exp,
					tracesdk.WithBatchTimeout(1*time.Second),
				),
				tracesdk.WithResource(resource.NewWithAttributes(
