package main

import (
	"context"
	"fmt"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/auth"
	"go.flipt.io/flipt/internal/storage/auth/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc/metadata"
)

// TestRegression covers two authentication bugs:
// 1. Cookie-based tokens are not extracted from HTTP cookies
// 2. Authentication middleware is enforced on all servers with no per-server bypass
func TestRegression(t *testing.T) {
	// Set up in-memory auth store
	authStore := memory.NewStore()

	// Create initial token for testing
	clientToken, _, err := authStore.CreateAuthentication(
		context.Background(),
		&memory.CreateAuthenticationRequest{
			Method: authrpc.Method_METHOD_TOKEN,
		},
	)
	require.NoError(t, err)
	require.NotEmpty(t, clientToken)

	logger := zaptest.NewLogger(t)

	t.Run("BUG: Cookie-based tokens are not extracted", func(t *testing.T) {
		// This test demonstrates that tokens sent via HTTP cookies are not accepted
		// Browsers naturally send tokens in cookies, but the auth middleware only checks
		// the Authorization header with Bearer format

		ctx := context.Background()
		interceptor := auth.UnaryInterceptor(logger, authStore)

		// Test 1: Token in proper Authorization header (should work)
		handlerCalled := false
		ctxWithAuth := metadata.NewIncomingContext(
			ctx,
			metadata.MD{
				"authorization": []string{fmt.Sprintf("Bearer %s", clientToken)},
			},
		)

		_, err := interceptor(ctxWithAuth, nil, nil, func(ctx context.Context, req interface{}) (interface{}, error) {
			handlerCalled = true
			return nil, nil
		})
		assert.NoError(t, err, "should authenticate successfully with Bearer token in Authorization header")
		assert.True(t, handlerCalled, "handler should have been called")

		// Test 2: Token in cookie header (should work but doesn't - BUG)
		// Simulate how browsers would send cookies in gRPC requests
		handlerCalled = false
		ctxWithCookie := metadata.NewIncomingContext(
			ctx,
			metadata.MD{
				"cookie": []string{fmt.Sprintf("flipt_client_token=%s", clientToken)},
			},
		)

		_, err = interceptor(ctxWithCookie, nil, nil, func(ctx context.Context, req interface{}) (interface{}, error) {
			handlerCalled = true
			return nil, nil
		})

		// This SHOULD work (token is valid and present) but fails because the middleware
		// doesn't check cookies
		if err == nil && handlerCalled {
			t.Skip("BUG FIXED: Cookies are now being extracted as tokens")
		}

		// Verify it fails with authentication error
		assert.Error(t, err, "cookie-based token should fail with unauthenticated error")
		assert.False(t, handlerCalled, "handler should not have been called due to auth failure")
		assert.True(
			t,
			strings.Contains(err.Error(), "Unauthenticated") ||
				strings.Contains(err.Error(), "unauthenticated"),
			"error should indicate unauthenticated, got: %v", err,
		)
	})

	t.Run("BUG: No per-service authentication bypass", func(t *testing.T) {
		// This test demonstrates that there's no way to configure specific services
		// (like authentication/delegation services) to skip authentication

		ctx := context.Background()
		interceptor := auth.UnaryInterceptor(logger, authStore)

		// Simulate trying to use an authentication service without a token
		// This would normally be needed for bootstrapping (creating the first token)
		ctxNoAuth := metadata.NewIncomingContext(ctx, metadata.MD{})

		handlerCalled := false
		_, err := interceptor(ctxNoAuth, nil, nil, func(ctx context.Context, req interface{}) (interface{}, error) {
			handlerCalled = true
			return nil, nil
		})

		// This SHOULD work for certain services in a properly designed system,
		// but fails because there's no way to skip authentication for specific services
		if err == nil && handlerCalled {
			t.Skip("BUG FIXED: Services can now skip authentication on a per-service basis")
		}

		// Verify it fails with authentication error
		assert.Error(t, err, "should fail because auth middleware is applied without exception")
		assert.False(t, handlerCalled, "handler should not have been called due to auth failure")
		assert.True(
			t,
			strings.Contains(err.Error(), "Unauthenticated") ||
				strings.Contains(err.Error(), "unauthenticated"),
			"error should indicate unauthenticated, got: %v", err,
		)

		// Architectural limitation: the interceptor is applied at the gRPC server level
		// to ALL methods, with no way to selectively disable it for specific services.
		// In the codebase, this means:
		// - All services go through the same interceptor chain
		// - There's no metadata/header to skip auth for bootstrap services
		// - The only way to run a service without auth is to create a separate gRPC server
	})

	t.Run("BUG: Global authentication enforcement", func(t *testing.T) {
		// This test demonstrates the architectural issue: all gRPC services
		// go through the same authentication interceptor chain with no exceptions

		// The ideal design would allow configuration like:
		//   grpcServer := NewGRPCServer()
		//   grpcServer.RegisterService(authService, skipAuth=true)  // <-- Not possible
		//   grpcServer.RegisterService(fliptService, skipAuth=false) // <-- Default

		// But the current implementation doesn't support this.
		// All services registered with the server go through the same chain.

		// Verify that both services are on the same server and both require auth
		authClient := authrpc.NewAuthenticationServiceClient(conn)
		fliptClient := pb.NewFliptClient(conn)

		ctx := context.Background()

		// Without auth, both should fail
		ctxNoAuth := metadata.AppendToOutgoingContext(ctx)

		// Auth service requires authentication
		_, err := authClient.ListAuthentications(ctxNoAuth, &authrpc.ListAuthenticationsRequest{})
		assert.Error(t, err, "auth service should require authentication")

		// Flipt service also requires authentication
		_, err = fliptClient.ListFlags(ctxNoAuth, &pb.ListFlagsRequest{})
		assert.Error(t, err, "flipt service should require authentication")

		// The architectural problem: there's no way to configure
		// the auth service to skip authentication while keeping it enabled for others
		assert.True(t, true, "both services share the same interceptor chain")
	})

	t.Run("Verify authentication works with proper Bearer token", func(t *testing.T) {
		// Sanity check: verify that valid Bearer tokens DO work
		ctxWithAuth := metadata.AppendToOutgoingContext(
			context.Background(),
			"authorization", fmt.Sprintf("Bearer %s", clientToken),
		)

		resp, err := client.CreateToken(ctxWithAuth, &authrpc.CreateTokenRequest{
			Name:        "valid-token",
			Description: "created with valid bearer token",
		})

		assert.NoError(t, err, "should succeed with valid bearer token")
		assert.NotNil(t, resp)
		assert.NotEmpty(t, resp.ClientToken)
	})
}

